pub fn process_instruction(program_id: &Pubkey, accounts: &[AccountInfo], _data: &[u8]) -> ProgramResult {
    let account_info_iter = &mut accounts.iter();
    let vault_account = next_account_info(account_info_iter)?;
    // Vulnerability: Missing `if vault_account.owner != program_id { return Err(...) }`
    let mut vault = Vault::try_from_slice(&vault_account.data.borrow())?;
    vault.unlocked = true;
    Ok(())
}

pub fn withdraw(ctx: Context<Withdraw>, amount: u64) -> Result<()> {
    let cpi_accounts = Transfer {
        from: ctx.accounts.vault.to_account_info(),
        to: ctx.accounts.user.to_account_info(),
        authority: ctx.accounts.vault_authority.to_account_info(),
    };
    // Vulnerability: token_program is caller-supplied and not verified against spl_token::ID
    let cpi_ctx = CpiContext::new(ctx.accounts.token_program.to_account_info(), cpi_accounts);
    token::transfer(cpi_ctx, amount)?;
    Ok(())
}

pub fn process_update(accounts: &[AccountInfo]) -> ProgramResult {
    let account_info_iter = &mut accounts.iter();
    let target_account = next_account_info(account_info_iter)?;
    // Vulnerability: Deserializing without validating the 8-byte discriminator prefix
    let mut data = target_account.data.borrow_mut();
    let mut admin_state = AdminState::try_from_slice(&data)?;
    admin_state.is_active = true;
    admin_state.serialize(&mut *data)?;
    Ok(())
}

