pub fn process_batch(ctx: Context<ProcessBatch>) -> Result<()> {
    // Vulnerability: Iterating through untrusted remaining_accounts with no key/owner validation
    for account_info in ctx.remaining_accounts.iter() {
        let mut data = account_info.data.borrow_mut();
        let mut state = BatchState::try_from_slice(&data)?;
        state.is_processed = true;
        state.serialize(&mut *data)?;
    }
    Ok(())
}

